import heapq
from typing import List, Optional

# Definition for singly-linked list.
# class ListNode:
#     def __init__(self, val=0, next=None):
#         self.val = val
#         self.next = next
class Solution:
    def mergeKLists(self, lists: List[Optional[ListNode]]) -> Optional[ListNode]:
        class Wrapper:
            def __init__(self, node):
                self.node = node
            def __lt__(self, other):
                return self.node.val < other.node.val

        queue = []
        for node in lists:
            if node:
                heapq.heappush(queue, Wrapper(node))

        dummy = ListNode()
        current = dummy

        while queue:
            wrapper = heapq.heappop(queue)
            current.next = wrapper.node
            current = current.next
            if current.next:
                heapq.heappush(queue, Wrapper(current.next))

        return dummy.next
